// Parse Runner-Up Careers (Markdown format with CAREER_SPLIT delimiter)
const input = $input.first().json.text;

// Get report_id from the same node that Split Top3 uses
const reportId = $('When Executed by Another Workflow').first().json.report_id;
const __lr = $('Get Report Language').first().json; const __lang = ((__lr && __lr.language) === 'nl') ? 'nl' : 'en';


// Split by the delimiter
const careerBlocks = input.split('---CAREER_SPLIT---').map(block => block.trim()).filter(Boolean);

const results = careerBlocks.map((block, index) => {
  // Extract career title (first # heading, not ## subheaders)
  const titleMatch = block.match(/^# ([^#].+)$/m);
  const career_title = titleMatch ? titleMatch[1].trim() : `Career ${index + 1}`;

  // Extract alternative titles and company size
  const altTitlesMatch = block.match(/\*\*Alternative titles:\*\* (.+?) \| \*\*At:\*\* (.+)/);
  const alternate_titles = altTitlesMatch ? altTitlesMatch[1].trim() : '';
  const company_size_type = altTitlesMatch ? altTitlesMatch[2].trim() : '';

  // Extract compatibility score
  const scoreMatch = block.match(/\*\*Compatibility score: (\d+)\/100\*\*/);
  const score = scoreMatch ? parseInt(scoreMatch[1], 10) : null;

  const moveMatch = block.match(/<!--move:(.*?)-->/i);
  const move = moveMatch ? moveMatch[1].trim() : null;

  // Build content language-agnostically: from the first "## " subheader
  // onward, drop any trailing "**More details" footer, and convert every
  // "## X" header to <h5>X</h5>. Works for English and Dutch headers alike.
  let __body = block;
  const __fh = __body.search(/^##\s+/m);
  if (__fh >= 0) __body = __body.slice(__fh);
  __body = __body.split(/\n\*\*More details/)[0];
  const sections = __body.replace(/^##\s+(.+?)\s*$/gm, '<h5>$1</h5>').replace(/<!--move:.*?-->/gi, '').trim();

  // Return one item per career (matches report_sections table structure)
  return {
    json: {
      title: `<h3><strong>${career_title}</strong></h3>`,
      alternate_titles: alternate_titles ? `<strong>Alternate titles:</strong> ${alternate_titles}` : '',
      company_size_type: company_size_type ? `<h4><strong>${company_size_type}</strong></h4>` : '',
      content: sections,
      score: score,
      report_id: reportId,
      metadata: move ? { move } : null,
      section_type: "runner_ups",
      order_number: index + 1,
      language: __lang
    }
  };
});

return results;

// Prepare data for Dream Job Feasibility prompt
const trigger = $('When Executed by Another Workflow').first().json;
return [{
  json: {
    'Top 3 careers': trigger.top_3_careers_str,
    'Runner up careers': trigger.runner_up_careers_str,
    'Outside box careers': trigger.outside_box_careers_str
  }
}];

// Get report_id from upstream node
const reportId = $('When Executed by Another Workflow').first().json.report_id;

// Get the dream jobs text from the upstream node
const fullText = $json.text;

// Subheaders to convert to h5 tags
const __lr = $('Get Report Language').first().json;
const __lang = ((__lr && __lr.language) === 'nl') ? 'nl' : 'en';
const DREAM_JOB_SUBHEADERS_ALL = {
  en: ["Overview","Feasibility Rating","Personality & Energy Fit","The Executive Version Suggestion","Industry Outlook & Regional Trends","Steps for Pursuing This Role"],
  nl: ["Overzicht","Haalbaarheidsscore","Aansluiting op persoonlijkheid en energie","De executive-versie","Sectorvooruitzichten en regionale trends","Stappen om deze rol na te streven"]
};
const DREAM_JOB_SUBHEADERS = DREAM_JOB_SUBHEADERS_ALL[__lang];

function formatDreamJobContent(content) {
  let formatted = content;

  DREAM_JOB_SUBHEADERS.forEach(subheader => {
    /**
     * Updated Regex:
     * 1. Looks for the subheader at the start of the string or after a newline
     * 2. Allows for optional Markdown stars (**)
     * 3. Allows for an optional colon (:)
     * 4. Ensures it matches the whole line to avoid replacing the word mid-sentence
     */
    const regex = new RegExp(`(^|\\n)\\*?\\*?${subheader}\\*?\\*?:?\\s*(\\n|$)`, 'gi');
    formatted = formatted.replace(regex, `$1<h5>${subheader}</h5>\n\n`);
  });

  // Convert markdown bold to <strong> — covers the feasibility rating,
  // which the prompt now bolds in full.
  formatted = formatted.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');

  return formatted.trim();
}

function parseDreamJob(content) {
  const lines = content.trim().split('\n');
  let title = '';
  let contentStartIndex = 0;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    // Match ## Title or just "Chief Product Officer" if it's the very first line
    if (line.match(/^##\s*.+$/) || (i === 0 && line.length > 0)) {
      title = line.replace(/^##\s*/, '').trim();
      contentStartIndex = i + 1;
      break;
    }
  }

  while (contentStartIndex < lines.length && lines[contentStartIndex].trim() === '') {
    contentStartIndex++;
  }

  const rawContent = lines.slice(contentStartIndex).join('\n').trim();
  const formattedContent = formatDreamJobContent(rawContent);

  return {
    title: title || 'Dream Job',
    content: formattedContent
  };
}

const dreamJobSections = fullText.split('---DREAM_JOB_SPLIT---');
const cleanSections = dreamJobSections.filter(section => section.trim().length > 0);

const records = cleanSections.map((section, index) => {
  const parsed = parseDreamJob(section);
  const moveMatch = section.match(/<!--move:(.*?)-->/i);
  const move = moveMatch ? moveMatch[1].trim() : null;
  const content = parsed.content.replace(/<!--move:.*?-->/gi, '').trim();

  return {
    json: {
      section_type: "dream_jobs",
      title: `<h3>${parsed.title}</h3>`,
      content: content,
      metadata: move ? { move } : null,
      report_id: reportId,
      order_number: index + 1,
      language: __lang
    }
  };
});

return records;

